"""GENERATED mixed audio+MIDI synthesis assets — inlined so mono+stereo+MIDI sessions build
with NO external control files. Regenerate via `donorpack.write_mixed_midi_data(control_root)`.
Sources: 'multiple track types no click fresh.ptx' (donor, internal order [1,0,2], base_n=3,
carries the MIDI containers) + '8 MIDI tracks.ptx' (single-digit MIDI unit template, track 2).
DONOR_LEAF = the donor's folder leaf; MIDI units carry no path so need no leaf."""
import base64 as _b64, zlib as _z

DONOR_LEAF = 'multiple track types'
_KEYS = ('b1057', 'b210b', 'b2620', 'b251a_0', 'b251a_1', 'b2589', 'name_entry')
_DONOR = ""
_TMPL = ""

def _dec(s): return _z.decompress(_b64.b64decode(s))
def mixed_midi_donor(): return _dec(_DONOR)   # [mono, MIDI, stereo] donor (base_n=3)
def midi_template():                          # extract_midi_unit dict (7 blocks)
    blob = _dec(_TMPL); o = 0; d = {}
    for k in _KEYS:
        n = int.from_bytes(blob[o:o + 4], "little"); o += 4; d[k] = blob[o:o + n]; o += n
    return d
